        "+      .map((m) => `${m.role === "user" ? "You" : "Assistant"}: ${m.content}`)",
        "+      .join("\n\n");",
        "+    await Clipboard.setStringAsync(text);",
        "+    setCopiedConvo(true);",
        "+    setTimeout(() => setCopiedConvo(false), 2000);",
