        "+            />",
        "+          </View>",
        "+        </TouchableBounce>",
        "+      </View>",
        "+    ),",
        "+    [threadStatus, id, actions, onStop, messages.length, copiedConvo, isDark]",
        "+  );",
        "+",
        "+  const statusColor = (() => {",
        "+    switch (threadStatus) {",
        "+      case "running":",
        "+        return AC.systemBlue;",
        "+      case "waiting":",
